SELECT COUNT(sample_id) AS sample_count
FROM leaf_samples
WHERE initials = 'AB';

SELECT COUNT(sample_id) AS total_samples
FROM sample_locations
WHERE location_id = 1;

SELECT leaf_area_cm2
FROM leaf_samples
WHERE sample_id = 1;

SELECT AVG(leaf_area_cm2) AS average_leaf_area
FROM leaf_samples
WHERE initials = 'AMB';

SELECT publication_title
FROM sample_publications
WHERE publication_date = '2020-07-29';

SELECT DISTINCT final_id
FROM leaf_samples
ORDER BY final_id;

SELECT final_id, AVG(leaf_area_cm2) AS avg_leaf_area
FROM leaf_samples
GROUP BY final_id;

SELECT final_id
FROM leaf_samples
ORDER BY final_id;
